96: void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::decodeHeaders(
97:     Http::ResponseHeaderMapPtr&& headers, bool end_stream) {
98:   const auto http_response_status = Http::Utility::getResponseStatus(*headers);
99:   if (http_response_status != enumToInt(Http::Code::OK)) {
100:     // https://github.com/grpc/grpc/blob/master/doc/http-grpc-status-mapping.md requires that
101:     // grpc-status be used if available.
102:     if (end_stream) {
103:       const auto grpc_status = Grpc::Common::getGrpcStatus(*headers);
104:       if (grpc_status) {
105:         onRpcComplete(grpc_status.value(), Grpc::Common::getGrpcMessage(*headers), true);
106:         return;
107:       }
108:     }
109:     onRpcComplete(Grpc::Utility::httpToGrpcStatus(http_response_status), "non-200 HTTP response",
110:                   end_stream);
111:     return;
112:   }
113:   if (!Grpc::Common::isGrpcResponseHeaders(*headers, end_stream)) {
114:     onRpcComplete(Grpc::Status::WellKnownGrpcStatus::Internal, "not a gRPC request", false);
115:     return;
116:   }
117:   if (end_stream) {
118:     // This is how, for instance, grpc-go signals about missing service - HTTP/2 200 OK with
119:     // 'unimplemented' gRPC status.
120:     const auto grpc_status = Grpc::Common::getGrpcStatus(*headers);
121:     if (grpc_status) {
122:       onRpcComplete(grpc_status.value(), Grpc::Common::getGrpcMessage(*headers), true);
123:       return;
124:     }
125:     onRpcComplete(Grpc::Status::WellKnownGrpcStatus::Internal,
126:                   "gRPC protocol violation: unexpected stream end", true);
127:   }
128: }
129: 
130: void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::decodeData(Buffer::Instance& data,
131:                                                                      bool end_stream) {
132:   if (end_stream) {
133:     onRpcComplete(Grpc::Status::WellKnownGrpcStatus::Internal,
134:                   "gRPC protocol violation: unexpected stream end", true);
135:     return;
136:   }
137:   // We should end up with only one frame here.
138:   std::vector<Grpc::Frame> decoded_frames;
139:   if (!decoder_.decode(data, decoded_frames).ok()) {
140:     onRpcComplete(Grpc::Status::WellKnownGrpcStatus::Internal, "gRPC wire protocol decode error",
141:                   false);
142:     return;
143:   }
144:   for (auto& frame : decoded_frames) {
145:     if (frame.length_ > 0) {
146:       if (health_check_response_) {
147:         // grpc.health.v1.Health.Check is unary RPC, so only one message is allowed.
148:         onRpcComplete(Grpc::Status::WellKnownGrpcStatus::Internal, "unexpected streaming", false);
149:         return;
150:       }
151:       health_check_response_ = std::make_unique<grpc::health::v1::HealthCheckResponse>();
152:       Buffer::ZeroCopyInputStreamImpl stream(std::move(frame.data_));
153: 
154:       if (frame.flags_ != Grpc::GRPC_FH_DEFAULT ||
155:           !health_check_response_->ParseFromZeroCopyStream(&stream)) {
156:         onRpcComplete(Grpc::Status::WellKnownGrpcStatus::Internal,
157:                       "invalid grpc.health.v1 RPC payload", false);
158:         return;
159:       }
160:     }
161:   }
162: }
