271: void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::onGoAway(
272:     Http::GoAwayErrorCode error_code) {
273:   ENVOY_CONN_LOG(debug, "connection going away health_flags={}", *client_,
274:                  HostUtility::healthFlagsToString(*host_));
275:   // If we have an active health check probe and receive a GOAWAY indicating
276:   // graceful shutdown, allow the probe to complete before closing the connection.
277:   // The connection will be closed when the active check completes or another
278:   // terminal condition occurs, such as a timeout or stream reset.
279:   if (request_encoder_ && error_code == Http::GoAwayErrorCode::NoError) {
280:     received_no_error_goaway_ = true;
281:     return;
282:   }
283: 
284:   // Even if we have active health check probe, fail it on GOAWAY and schedule new one.
285:   if (request_encoder_) {
286:     handleFailure(envoy::data::core::v3::NETWORK);
287:     // request_encoder_ can already be destroyed if the host was removed during the failure callback
288:     // above.
289:     if (request_encoder_ != nullptr) {
290:       expect_reset_ = true;
291:       request_encoder_->getStream().resetStream(Http::StreamResetReason::LocalReset);
292:     }
293:   }
294:   // client_ can already be destroyed if the host was removed during the failure callback above.
295:   if (client_ != nullptr) {
296:     client_->close(Network::ConnectionCloseType::Abort);
297:   }
298: }
